from typing import List, Tuple


def build_tree(manager: List[int]):
    tree = {}
    for i in range(len(manager)):
        employee,m = i,manager[i]
        if(m == -1):
            tree[employee] = []
            continue
        employees = tree.get(m,[])
        employees.append(employee)
        tree[m] = employees
    return tree

