using System;
using System.Collections.Generic;

public class Solution
{
    public int MaxTotalFun(int[] manager, int[] funRating)
    {
        int n = manager.Length;

        // Build adjacency list (children for each manager)
        List<int>[] children = new List<int>[n];
        for (int i = 0; i < n; i++)
        {
            children[i] = new List<int>();
        }

        int root = -1;
        for (int i = 0; i < n; i++)
        {
            if (manager[i] == -1)
            {
                root = i;
            }
            else
            {
                children[manager[i]].Add(i);
            }
        }

        // DP arrays
        int[] include = new int[n];  // include[i] = max fun if we include i
        int[] exclude = new int[n];  // exclude[i] = max fun if we exclude i
        bool[] visited = new bool[n];

        // DFS with recursion
        void Dfs(int u)
        {
            visited[u] = true;

            include[u] = funRating[u];  // if we include u, start with its fun
            exclude[u] = 0;

            foreach (int v in children[u])
            {
                if (!visited[v])
                {
                    Dfs(v);

                    // If we include u, we must exclude v
                    include[u] += exclude[v];

                    // If we exclude u, we can choose best for each child
                    exclude[u] += Math.Max(include[v], exclude[v]);
                }
            }
        }

        Dfs(root);

        // Best result for the root: either include or exclude it
        return Math.Max(include[root], exclude[root]);
    }
}
